html:
{% set currency = doc.currency or frappe.defaults.get_user_default('currency') %}
<!DOCTYPE html>
<html dir="rtl" lang="ar">
<head>
<meta charset="UTF-8">
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: 'Segoe UI', Arial, sans-serif;
    font-size: 12px;
    color: #333;
    background: #fff;
    direction: rtl;
  }
  .page-wrapper { padding: 20px 30px; }

  /* ─── Header ─── */
  .header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    border-bottom: 3px solid #f97316;
    padding-bottom: 14px;
    margin-bottom: 18px;
  }
  .header .brand {
    text-align: center;
    flex: 1;
  }
  .header .brand h1 {
    font-size: 26px;
    color: #f97316;
    font-weight: 700;
    letter-spacing: 1px;
  }
  .header .brand p {
    font-size: 11px;
    color: #888;
    margin-top: 2px;
  }
  .header .doc-info {
    text-align: left;
    min-width: 160px;
  }
  .header .doc-info .doc-title {
    font-size: 16px;
    font-weight: 700;
    color: #f97316;
    text-transform: uppercase;
  }
  .header .doc-info table td {
    padding: 2px 4px;
    font-size: 11px;
    color: #555;
  }
  .header .doc-info table td:first-child { font-weight: 600; color: #333; }

  /* ─── Party section ─── */
  .party-section {
    display: flex;
    gap: 20px;
    margin-bottom: 18px;
  }
  .party-box {
    flex: 1;
    background: #fff8f0;
    border: 1px solid #fed7aa;
    border-radius: 8px;
    padding: 12px 14px;
  }
  .party-box h3 {
    font-size: 11px;
    font-weight: 700;
    color: #f97316;
    text-transform: uppercase;
    margin-bottom: 6px;
    border-bottom: 1px solid #fed7aa;
    padding-bottom: 4px;
  }
  .party-box p { font-size: 12px; line-height: 1.7; color: #444; }

  /* ─── Items table ─── */
  .items-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 18px;
    font-size: 12px;
  }
  .items-table thead tr {
    background: #f97316;
    color: #fff;
  }
  .items-table thead th {
    padding: 8px 10px;
    text-align: center;
    font-weight: 600;
    white-space: nowrap;
  }
  .items-table tbody tr:nth-child(even) { background: #fff7ed; }
  .items-table tbody tr:hover { background: #ffedd5; }
  .items-table tbody td {
    padding: 7px 10px;
    border-bottom: 1px solid #fed7aa;
    text-align: center;
    vertical-align: middle;
  }
  .items-table tbody td.description { text-align: right; }

  /* ─── Totals ─── */
  .totals-wrapper {
    display: flex;
    justify-content: flex-start;
    margin-bottom: 22px;
  }
  .totals-box {
    min-width: 260px;
    background: #fff8f0;
    border: 1px solid #fed7aa;
    border-radius: 8px;
    overflow: hidden;
  }
  .totals-box table { width: 100%; border-collapse: collapse; }
  .totals-box table td {
    padding: 7px 14px;
    font-size: 12px;
    border-bottom: 1px solid #fed7aa;
  }
  .totals-box table td:last-child { text-align: left; }
  .totals-box .grand-total td {
    background: #f97316;
    color: #fff;
    font-size: 14px;
    font-weight: 700;
    border: none;
  }

  /* ─── Footer ─── */
  .footer {
    border-top: 2px solid #f97316;
    padding-top: 14px;
    margin-top: 10px;
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    gap: 20px;
  }
  .signature-area {
    flex: 1;
    text-align: center;
  }
  .signature-area .line {
    border-top: 1px solid #aaa;
    margin-top: 36px;
    margin-bottom: 4px;
  }
  .signature-area p { font-size: 11px; color: #777; }
  .footer-notes {
    flex: 2;
    font-size: 11px;
    color: #666;
    background: #f9fafb;
    border: 1px solid #e5e7eb;
    border-radius: 6px;
    padding: 10px 12px;
  }
  .footer-contact {
    flex: 1;
    font-size: 11px;
    color: #555;
    text-align: center;
  }
  .footer-contact .co-name {
    font-weight: 700;
    color: #f97316;
    font-size: 13px;
    margin-bottom: 4px;
  }

  /* ─── Watermark badge ─── */
  .status-badge {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 12px;
    font-size: 10px;
    font-weight: 700;
    text-transform: uppercase;
  }
  .badge-paid   { background: #dcfce7; color: #16a34a; }
  .badge-unpaid { background: #fef9c3; color: #ca8a04; }
  .badge-return { background: #fee2e2; color: #dc2626; }
</style>
</head>
<body>
<div class="page-wrapper">

  <!-- ══════════ HEADER ══════════ -->
  <div class="header">
    <div class="brand">
      <h1>بيت الشاورما</h1>
      <p>{{ doc.company }}</p>
    </div>
    <div class="doc-info">
      <div class="doc-title">فاتورة مبيعات</div>
      <table>
        <tr><td>رقم الفاتورة:</td><td>{{ doc.name }}</td></tr>
        <tr><td>التاريخ:</td><td>{{ frappe.format(doc.posting_date, 'Date') }}</td></tr>
        {% if doc.due_date %}
        <tr><td>تاريخ الاستحقاق:</td><td>{{ frappe.format(doc.due_date, 'Date') }}</td></tr>
        {% endif %}
        <tr><td>الحالة:</td><td>
          {% if doc.outstanding_amount == 0 %}
            <span class="status-badge badge-paid">مدفوعة</span>
          {% elif doc.outstanding_amount < 0 %}
            <span class="status-badge badge-return">مرتجع</span>
          {% else %}
            <span class="status-badge badge-unpaid">غير مدفوعة</span>
          {% endif %}
        </td></tr>
      </table>
    </div>
  </div>

  <!-- ══════════ PARTY ══════════ -->
  <div class="party-section">
    <div class="party-box">
      <h3>بيانات العميل</h3>
      <p><strong>{{ doc.customer_name or doc.customer }}</strong></p>
      {% if doc.customer_address %}<p>{{ doc.customer_address }}</p>{% endif %}
      {% if doc.contact_mobile %}<p>📞 {{ doc.contact_mobile }}</p>{% endif %}
    </div>
    <div class="party-box">
      <h3>بيانات الشركة</h3>
      <p><strong>{{ doc.company }}</strong></p>
      {% set co = frappe.get_doc('Company', doc.company) %}
      {% if co.address %}<p>{{ co.address }}</p>{% endif %}
      {% if co.phone_no %}<p>📞 {{ co.phone_no }}</p>{% endif %}
    </div>
  </div>

  <!-- ══════════ ITEMS TABLE ══════════ -->
  <table class="items-table">
    <thead>
      <tr>
        <th>#</th>
        <th>الصنف</th>
        <th>الوصف</th>
        <th>الكمية</th>
        <th>الوحدة</th>
        <th>البراند</th>
        <th>سعر الوحدة</th>
        <th>الخصم %</th>
        <th>الإجمالي</th>
      </tr>
    </thead>
    <tbody>
      {% for row in doc.items %}
      <tr>
        <td>{{ loop.index }}</td>
        <td>{{ row.item_code }}</td>
        <td class="description">{{ row.item_name }}</td>
        <td>{{ row.qty }}</td>
        <td>{{ row.uom }}</td>
        <td>{{ row.custom_item_brand or '—' }}</td>
        <td>{{ frappe.format(row.rate, 'Currency') }}</td>
        <td>{{ row.discount_percentage or 0 }}%</td>
        <td>{{ frappe.format(row.amount, 'Currency') }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <!-- ══════════ TOTALS ══════════ -->
  <div class="totals-wrapper">
    <div class="totals-box">
      <table>
        <tr><td>المجموع الفرعي</td><td>{{ frappe.format(doc.net_total, 'Currency') }}</td></tr>
        {% if doc.discount_amount %}
        <tr><td>الخصم</td><td>- {{ frappe.format(doc.discount_amount, 'Currency') }}</td></tr>
        {% endif %}
        {% if doc.total_taxes_and_charges %}
        <tr><td>الضرائب والرسوم</td><td>{{ frappe.format(doc.total_taxes_and_charges, 'Currency') }}</td></tr>
        {% endif %}
        <tr class="grand-total">
          <td>الإجمالي النهائي</td>
          <td>{{ frappe.format(doc.grand_total, 'Currency') }} {{ currency }}</td>
        </tr>
      </table>
    </div>
  </div>

  <!-- ══════════ FOOTER ══════════ -->
  <div class="footer">
    <div class="signature-area">
      <div class="line"></div>
      <p>توقيع المستلم</p>
    </div>
    <div class="footer-notes">
      {% if doc.terms %}
      <strong>ملاحظات:</strong><br>{{ doc.terms }}
      {% else %}
      <strong>ملاحظات:</strong><br>شكراً لتعاملكم معنا — بيت الشاورما
      {% endif %}
    </div>
    <div class="footer-contact">
      <div class="co-name">بيت الشاورما</div>
      <p>{{ doc.company }}</p>
      {% set co = frappe.get_doc('Company', doc.company) %}
      {% if co.phone_no %}<p>📞 {{ co.phone_no }}</p>{% endif %}
      {% if co.email %}<p>✉ {{ co.email }}</p>{% endif %}
    </div>
    <div class="signature-area">
      <div class="line"></div>
      <p>توقيع المُصدِر</p>
    </div>
  </div>

</div>
</body>
</html>
